1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / processing fee
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
8	    expect(quote(customer, [])).toBe(5);
9	  });
10	
11	  // Base premiums for single items (with first insurance + fee, newcomer)
12	  it("quote for a single plain sword (newcomer, no contracts) yields 115 G (100 base + 10 first + 5 fee)", () => {
13	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
14	    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
15	    expect(quote(customer, [sword])).toBe(115);
16	  });
17	  it("quote for a single plain amulet (newcomer) yields 71 G (60 base + 6 first + 5 fee)", () => {
18	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
19	    const amulet = { type: "amulet", material: "silver", enchantment: 2, cursed: false };
20	    expect(quote(customer, [amulet])).toBe(71);
21	  });
22	  it("quote for a single plain staff (newcomer) yields 93 G (80 base + 8 first + 5 fee)", () => {
23	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
24	    const staff = { type: "staff", material: "wood", enchantment: 0, cursed: false };
25	    expect(quote(customer, [staff])).toBe(93);
26	  });
27	  it.todo("quote for a single plain potion (newcomer) yields 49 G (40 base + 4 first + 5 fee)");
28	
29	  // Components base premiums
30	  it.todo("quote for 2 runes yields base premium 50 G (no block applies)");
31	  it.todo("quote for 3 runes yields base premium 60 G (block of 3 alike applies)");
32	  it.todo("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)");
33	  it.todo("quote for 7 runes yields base premium 175 G (one block of 3 + 4 individual)");
34	
35	  // "Alike" components — same type
36	  it.todo("quote for 2 runes + 1 moonstone yields base premium 75 G (no block, different types)");
37	  it.todo("quote for 3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
38	
39	  // Item-specific modifiers
40	  it.todo("cursed sword adds 50% surcharge to that item's base premium");
41	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
42	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
43	  it.todo("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
44	
45	  // Modifier scope on multi-item policies
46	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base (210 G before policy modifiers + fee)");
47	
48	  // Policy-wide modifiers
49	  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
50	  it.todo("first insurance adds 10% surcharge to policy base");
51	  it.todo("follow-up contract gives 15% discount on policy base");
52	
53	  // Processing fee added at the end
54	  it.todo("5 G processing fee is always added after all other modifiers");
55	
56	  // Rounding
57	  it.todo("premium of 197.5 G is rounded UP to 198 G");
58	
59	  // Integration: Newcomer with cursed sword
60	  it.todo("newcomer (0 years, no previous) with cursed sword (steel, ench 3) yields premium 165 G");
61	
62	  // Integration: Long-standing customer's second contract
63	  it.todo("3-year customer's second contract: cursed sword (steel, ench 7) yields premium 160 G");
64	
65	  // CLAIM PROCESSING — basic
66	  it.todo("standard sword damage 500 G yields payout 400 G (500 - 100 deductible)");
67	  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");
68	
69	  // Claim payout rounding
70	  it.todo("payout of 350.5 G is rounded DOWN to 350 G");
71	
72	  // Deductible per damage event
73	  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");
74	
75	  // Special reimbursement clauses
76	  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
77	  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
78	  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
79	  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");
80	
81	  // Cap
82	  it.todo("sword policy (sum 1000, cap 2000): two claims of 1500 each yield first payout 1400 G with cap 600 remaining");
83	  it.todo("sword policy second claim of 1500 G with 600 G cap remaining yields payout 600 G and cap 0");
84	  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
85	  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount affects only premium, not insurance sum)");
86	
87	  // Multiple items of same type
88	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
89	  it.todo("two sword damage entries each get their own deductible when both swords are insured");
90	  it.todo("two sword damage entries when only one sword is insured: claim is rejected");
91	
92	  // Error cases
93	  it.todo("quote with unknown item type (e.g. broomstick): exits non-zero with stderr message");
94	  it.todo("claim referencing item not in policy: exits non-zero with stderr message");
95	  it.todo("claim with negative damage amount: exits non-zero with stderr message");
96	
97	  // CLI integration
98	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout");
99	  it.todo("CLI processes sequential steps; claim refers to earlier quote by zero-based step index");
100	});
101

1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	export function quote(customer: Customer, items: Item[]): number {
20	  const basePremium = items.reduce(
21	    (sum, item) => sum + (BASE_PREMIUMS[item.type] * 11) / 10,
22	    0,
23	  );
24	  return Math.ceil(basePremium) + PROCESSING_FEE;
25	}
